import React, { useState, useEffect, useRef, useCallback, useReducer } from 'react';
import { useAuth } from '../context/AuthContext';
import { useSocket } from '../context/SocketContext';
import axios from 'axios';
import './Board.css';
import API from '../context/API';

axios.defaults.baseURL = API;
// Reducer for board state
const boardReducer = (state, action) => {
  switch (action.type) {
    case 'SET_BOARD':
      return { ...state, boxes: action.boxes || [], wires: action.wires || [], boardId: action.boardId };
    case 'ADD_BOX':
      return { ...state, boxes: [...state.boxes, action.box] };
    case 'UPDATE_BOX':
      return {
        ...state,
        boxes: state.boxes.map(b => b._id === action.box._id ? action.box : b)
      };
    case 'DELETE_BOX':
      return {
        ...state,
        boxes: state.boxes.filter(b => b._id !== action.boxId),
        wires: state.wires.filter(w => w.fromId !== action.boxId && w.toId !== action.boxId)
      };
    case 'UPDATE_WIRES':
      return { ...state, wires: action.wires };
    case 'REMOVE_WIRE':
      return {
        ...state,
        wires: state.wires.filter(w => !(w.fromId === action.fromId && w.toId === action.toId))
      };
    case 'MERGE_BOARD':
      const incomingBoxIds = new Set(action.boxes.map(b => b._id));
      const existingBoxes = state.boxes.filter(b => !incomingBoxIds.has(b._id));
      return {
        ...state,
        boxes: [...existingBoxes, ...action.boxes],
        wires: action.wires,
        boardId: action.boardId || state.boardId
      };
    default:
      return state;
  }
};

const Board = () => {
  const { user, users, fetchActiveUsers } = useAuth();
  const { socket, isConnected } = useSocket();
  const [state, dispatch] = useReducer(boardReducer, { boxes: [], wires: [], boardId: null });
  const [selectedIds, setSelectedIds] = useState(new Set());
  const [dragging, setDragging] = useState(null);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const [boardOffset, setBoardOffset] = useState({ x: 0, y: 0 });
  const [zoom, setZoom] = useState(1);
  const [isPanning, setIsPanning] = useState(false);
  const [panStart, setPanStart] = useState({ x: 0, y: 0 });
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [showImageModal, setShowImageModal] = useState(false);
  const [showLinkModal, setShowLinkModal] = useState(false);
  const [imageUrl, setImageUrl] = useState('');
  const [linkTitle, setLinkTitle] = useState('');
  const [linkUrl, setLinkUrl] = useState('');
  
  const boardRef = useRef(null);
  const canvasRef = useRef(null);
  const nextId = useRef(1);
  const saveTimeout = useRef(null);
  const dragStartPosition = useRef(null);
  const isDraggingRef = useRef(false);
  const mouseDownTime = useRef(0);
  const mouseDownPos = useRef({ x: 0, y: 0 });
  const isResizing = useRef(false);
  const resizeBoxId = useRef(null);
  const resizeStartPos = useRef({ x: 0, y: 0 });
  const resizeStartScale = useRef(1);
  const resizeCurrentScale = useRef(1);

  // Load global board
  useEffect(() => {
    loadGlobalBoard();
    fetchActiveUsers();
    
    const interval = setInterval(fetchActiveUsers, 5000);
    return () => clearInterval(interval);
  }, []);

  // Socket listeners
  useEffect(() => {
    if (!socket || !isConnected) {
      console.log('Socket not available or not connected');
      return;
    }

    console.log('Setting up socket listeners, connected:', isConnected);

    socket.on('board-state', (data) => {
      console.log('Received board state');
      dispatch({ 
        type: 'SET_BOARD', 
        boxes: data.boxes, 
        wires: data.wires,
        boardId: data.boardId 
      });
      const maxId = Math.max(...(data.boxes || []).map(b => parseInt(b._id) || 0), 0);
      nextId.current = maxId + 1;
      setIsLoading(false);
    });

    socket.on('box-created', (data) => {
      if (data.userId !== user?._id) {
        console.log('Box created by:', data.username);
        const exists = state.boxes.some(b => b._id === data.box._id);
        if (!exists) {
          dispatch({ type: 'ADD_BOX', box: data.box });
        }
      }
    });

    socket.on('box-updated', (data) => {
      if (data.userId !== user?._id) {
        console.log('Box updated by:', data.username);
        dispatch({ type: 'UPDATE_BOX', box: data.box });
      }
    });

    socket.on('box-deleted', (data) => {
      if (data.userId !== user?._id) {
        console.log('Box deleted by:', data.username);
        dispatch({ type: 'DELETE_BOX', boxId: data.boxId });
        setSelectedIds(prev => {
          const newSet = new Set(prev);
          newSet.delete(data.boxId);
          return newSet;
        });
      }
    });

    socket.on('wire-updated', (data) => {
      console.log('Wire updated by:', data.username);
      dispatch({ type: 'UPDATE_WIRES', wires: data.wires });
    });

    socket.on('wire-removed', (data) => {
      console.log('Wire removed by:', data.username, 'from:', data.fromId, 'to:', data.toId);
      dispatch({ type: 'REMOVE_WIRE', fromId: data.fromId, toId: data.toId });
    });

    socket.on('position-changed', (data) => {
      if (data.userId !== user?._id) {
        console.log('Position changed by:', data.username);
        dispatch({ 
          type: 'UPDATE_BOX', 
          box: { ...state.boxes.find(b => b._id === data.boxId), x: data.x, y: data.y } 
        });
      }
    });

    socket.on('user-joined', (data) => {
      console.log('User joined:', data.username);
      fetchActiveUsers();
    });

    socket.on('user-left', (data) => {
      console.log('User left:', data.username);
      fetchActiveUsers();
    });

    return () => {
      console.log('Cleaning up socket listeners');
      socket.off('board-state');
      socket.off('box-created');
      socket.off('box-updated');
      socket.off('box-deleted');
      socket.off('wire-updated');
      socket.off('wire-removed');
      socket.off('position-changed');
      socket.off('user-joined');
      socket.off('user-left');
    };
  }, [socket, isConnected, state.boxes, user]);

  const loadGlobalBoard = async () => {
    try {
      console.log('Loading global board...');
      const res = await axios.get('/api/board/global');
      if (res.data) {
        console.log('Global board loaded');
        dispatch({ 
          type: 'SET_BOARD', 
          boxes: res.data.boxes || [], 
          wires: res.data.wires || [],
          boardId: res.data._id
        });
        const maxId = Math.max(...(res.data.boxes || []).map(b => parseInt(b._id) || 0), 0);
        nextId.current = maxId + 1;
      }
    } catch (error) {
      console.error('Error loading global board:', error);
    } finally {
      setIsLoading(false);
    }
  };

  // Save board with debounce
  const saveBoard = useCallback(async () => {
    if (!state.boardId || isSaving) return;
    
    if (saveTimeout.current) {
      clearTimeout(saveTimeout.current);
    }

    saveTimeout.current = setTimeout(async () => {
      setIsSaving(true);
      try {
        await axios.put(`/api/board/global`, {
          boxes: state.boxes,
          wires: state.wires
        });
        console.log('Board saved to database');
      } catch (error) {
        console.error('Error saving board:', error);
      } finally {
        setIsSaving(false);
      }
    }, 500);
  }, [state.boardId, state.boxes, state.wires, isSaving]);

  // ----- ADD BOX WITH MODALS -----
  const addTextBox = useCallback(() => {
    const id = nextId.current++;
    const newBox = {
      _id: id.toString(),
      x: 100 + Math.random() * 200,
      y: 100 + Math.random() * 200,
      text: `Text ${id}`,
      borderColor: `hsl(${Math.floor(Math.random() * 360)}, 80%, 70%)`,
      textColor: '#f0f0f0',
      wireColor: `hsl(${Math.floor(Math.random() * 360)}, 85%, 65%)`,
      scale: 1,
      isImage: false,
      isLink: false
    };
    
    dispatch({ type: 'ADD_BOX', box: newBox });
    
    if (socket && isConnected) {
      socket.emit('box-created', { box: newBox });
    }
    
    saveBoard();
  }, [socket, isConnected, saveBoard]);

  const addImageBox = useCallback(() => {
    if (!imageUrl.trim()) {
      alert('Please enter an image URL');
      return;
    }
    
    try {
      new URL(imageUrl);
    } catch (e) {
      alert('Please enter a valid URL (include https://)');
      return;
    }
    
    const id = nextId.current++;
    const newBox = {
      _id: id.toString(),
      x: 100 + Math.random() * 200,
      y: 100 + Math.random() * 200,
      text: 'Image',
      imageUrl: imageUrl,
      borderColor: `hsl(${Math.floor(Math.random() * 360)}, 80%, 70%)`,
      wireColor: `hsl(${Math.floor(Math.random() * 360)}, 85%, 65%)`,
      scale: 1,
      isImage: true,
      isLink: false
    };
    
    dispatch({ type: 'ADD_BOX', box: newBox });
    
    if (socket && isConnected) {
      socket.emit('box-created', { box: newBox });
    }
    
    setImageUrl('');
    setShowImageModal(false);
    saveBoard();
  }, [imageUrl, socket, isConnected, saveBoard]);

  const addLinkBox = useCallback(() => {
    if (!linkUrl.trim()) {
      alert('Please enter a URL');
      return;
    }
    
    if (!linkTitle.trim()) {
      alert('Please enter a title');
      return;
    }
    
    try {
      new URL(linkUrl);
    } catch (e) {
      alert('Please enter a valid URL (include https://)');
      return;
    }
    
    const id = nextId.current++;
    const newBox = {
      _id: id.toString(),
      x: 100 + Math.random() * 200,
      y: 100 + Math.random() * 200,
      text: linkTitle,
      linkUrl: linkUrl,
      borderColor: `hsl(${Math.floor(Math.random() * 360)}, 80%, 70%)`,
      textColor: '#4a9eff',
      wireColor: `hsl(${Math.floor(Math.random() * 360)}, 85%, 65%)`,
      scale: 1,
      isImage: false,
      isLink: true
    };
    
    dispatch({ type: 'ADD_BOX', box: newBox });
    
    if (socket && isConnected) {
      socket.emit('box-created', { box: newBox });
    }
    
    setLinkTitle('');
    setLinkUrl('');
    setShowLinkModal(false);
    saveBoard();
  }, [linkTitle, linkUrl, socket, isConnected, saveBoard]);

  // ----- DELETE -----
  const deleteSelected = useCallback(() => {
    if (selectedIds.size === 0) return;
    if (!window.confirm(`Delete ${selectedIds.size} box(es)?`)) return;
    
    const ids = new Set(selectedIds);
    
    ids.forEach(boxId => {
      dispatch({ type: 'DELETE_BOX', boxId });
      if (socket && isConnected) {
        socket.emit('box-deleted', { boxId });
      }
    });
    
    setSelectedIds(new Set());
    saveBoard();
  }, [selectedIds, socket, isConnected, saveBoard]);

  // ----- CONNECT SELECTED BOXES -----
  const connectSelected = useCallback(() => {
    const ids = [...selectedIds];
    if (ids.length < 2) {
      alert('Select at least 2 boxes (Ctrl+click to multi-select)');
      return;
    }
    
    const newWires = [...state.wires];
    let wiresAdded = 0;
    
    for (let i = 0; i < ids.length - 1; i++) {
      for (let j = i + 1; j < ids.length; j++) {
        const fromId = ids[i];
        const toId = ids[j];
        
        const exists = newWires.some(w => 
          (w.fromId === fromId && w.toId === toId) || 
          (w.fromId === toId && w.toId === fromId)
        );
        
        if (!exists) {
          newWires.push({ fromId, toId });
          wiresAdded++;
        }
      }
    }
    
    if (wiresAdded === 0) {
      alert('Wires already exist between all selected boxes');
      return;
    }
    
    dispatch({ type: 'UPDATE_WIRES', wires: newWires });
    
    if (socket && isConnected) {
      socket.emit('wire-updated', { wires: newWires });
    }
    
    setSelectedIds(new Set());
    saveBoard();
  }, [selectedIds, state.wires, socket, isConnected, saveBoard]);

  // ----- DISCONNECT WIRE BETWEEN SELECTED BOXES -----
  const disconnectSelected = useCallback(() => {
    const ids = [...selectedIds];
    if (ids.length < 2) {
      alert('Select at least 2 boxes (Ctrl+click to multi-select) to disconnect the wire between them');
      return;
    }
    
    let wiresToRemove = [];
    const wireSet = new Set();
    
    for (let i = 0; i < ids.length - 1; i++) {
      for (let j = i + 1; j < ids.length; j++) {
        const fromId = ids[i];
        const toId = ids[j];
        
        const wire = state.wires.find(w => 
          (w.fromId === fromId && w.toId === toId) || 
          (w.fromId === toId && w.toId === fromId)
        );
        
        if (wire) {
          const key = [wire.fromId, wire.toId].sort().join('-');
          if (!wireSet.has(key)) {
            wireSet.add(key);
            wiresToRemove.push({ fromId: wire.fromId, toId: wire.toId });
          }
        }
      }
    }
    
    if (wiresToRemove.length === 0) {
      alert('No wires found between the selected boxes');
      return;
    }
    
    if (!window.confirm(`Remove ${wiresToRemove.length} wire(s) between the selected boxes?`)) return;
    
    wiresToRemove.forEach(({ fromId, toId }) => {
      console.log('Removing wire:', fromId, toId);
      dispatch({ type: 'REMOVE_WIRE', fromId, toId });
    });
    
    const updatedWires = state.wires.filter(w => {
      return !wiresToRemove.some(r => 
        (r.fromId === w.fromId && r.toId === w.toId) ||
        (r.fromId === w.toId && r.toId === w.fromId)
      );
    });
    
    if (socket && isConnected) {
      console.log('Emitting wire-updated with removed wires');
      socket.emit('wire-updated', { wires: updatedWires });
      
      wiresToRemove.forEach(({ fromId, toId }) => {
        socket.emit('wire-removed', { fromId, toId });
      });
    }
    
    setSelectedIds(new Set());
    saveBoard();
  }, [selectedIds, state.wires, socket, isConnected, saveBoard]);

  // ----- IMAGE ZOOM -----
  const openImageZoom = useCallback((imageUrl, text) => {
    const overlay = document.createElement('div');
    overlay.className = 'image-zoom-overlay';
    overlay.style.cssText = `
      position: fixed;
      top: 0;
      left: 0;
      width: 100vw;
      height: 100vh;
      background: rgba(0, 0, 0, 0.92);
      backdrop-filter: blur(8px);
      z-index: 1000;
      display: flex;
      align-items: center;
      justify-content: center;
      flex-direction: column;
      cursor: pointer;
    `;
    
    const img = document.createElement('img');
    img.src = imageUrl;
    img.alt = text || 'Image';
    img.style.cssText = `
      max-width: 90vw;
      max-height: 80vh;
      object-fit: contain;
      border-radius: 16px;
      box-shadow: 0 20px 60px rgba(0,0,0,0.8);
      border: 2px solid #555;
    `;
    
    const label = document.createElement('div');
    label.textContent = text || 'Image';
    label.style.cssText = `
      color: #aaa;
      margin-top: 20px;
      font-size: 0.9rem;
      background: rgba(0,0,0,0.5);
      padding: 8px 20px;
      border-radius: 30px;
      max-width: 80vw;
      overflow: hidden;
      text-overflow: ellipsis;
      white-space: nowrap;
    `;
    
    const closeBtn = document.createElement('button');
    closeBtn.textContent = '✕';
    closeBtn.style.cssText = `
      position: absolute;
      top: 30px;
      right: 40px;
      background: rgba(255,255,255,0.15);
      border: 2px solid rgba(255,255,255,0.3);
      color: white;
      font-size: 1.8rem;
      width: 60px;
      height: 60px;
      border-radius: 50%;
      cursor: pointer;
      transition: 0.2s;
      display: flex;
      align-items: center;
      justify-content: center;
      font-weight: 300;
    `;
    closeBtn.onmouseover = () => {
      closeBtn.style.background = 'rgba(255,50,50,0.3)';
      closeBtn.style.borderColor = '#ff6b6b';
    };
    closeBtn.onmouseout = () => {
      closeBtn.style.background = 'rgba(255,255,255,0.15)';
      closeBtn.style.borderColor = 'rgba(255,255,255,0.3)';
    };
    
    overlay.appendChild(closeBtn);
    overlay.appendChild(img);
    overlay.appendChild(label);
    
    overlay.onclick = (e) => {
      if (e.target === overlay) {
        document.body.removeChild(overlay);
      }
    };
    
    closeBtn.onclick = (e) => {
      e.stopPropagation();
      document.body.removeChild(overlay);
    };
    
    document.body.appendChild(overlay);
  }, []);

  // ----- UPDATE BOX -----
  const updateBox = useCallback((box) => {
    dispatch({ type: 'UPDATE_BOX', box });
    if (socket && isConnected) {
      socket.emit('box-updated', { box });
    }
    saveBoard();
  }, [socket, isConnected, saveBoard]);

  // ----- UNIVERSAL COLOR CHANGE HANDLING -----
  const handleColorChange = useCallback((e, box, colorType) => {
    const colorValue = e.target.value;
    
    // Direct DOM manipulation for immediate visual feedback
    const boxElement = document.querySelector(`[data-id="${box._id}"]`);
    if (boxElement) {
      if (colorType === 'borderColor') {
        boxElement.style.borderColor = colorValue;
        boxElement.style.setProperty('border-color', colorValue);
        boxElement.style.border = `3px solid ${colorValue}`;
      } else if (colorType === 'textColor') {
        const textElement = boxElement.querySelector('.box-text, .link-title');
        if (textElement) {
          textElement.style.color = colorValue;
        }
      }
    }
    
    // Update state immediately
    const updatedBox = { ...box, [colorType]: colorValue };
    dispatch({ type: 'UPDATE_BOX', box: updatedBox });
    
    // Sync via socket
    if (socket && isConnected) {
      socket.emit('box-updated', { box: updatedBox });
    }
    
    // Save to database
    saveBoard();
  }, [socket, isConnected, saveBoard]);

  // ----- ZOOM CONTROLS -----
  const zoomIn = useCallback(() => {
    const newZoom = Math.min(3, zoom + 0.1);
    const rect = boardRef.current?.getBoundingClientRect();
    if (rect) {
      const centerX = rect.width / 2;
      const centerY = rect.height / 2;
      setBoardOffset(prev => ({
        x: prev.x + (centerX / zoom - centerX / newZoom),
        y: prev.y + (centerY / zoom - centerY / newZoom)
      }));
    }
    setZoom(newZoom);
  }, [zoom]);

  const zoomOut = useCallback(() => {
    const newZoom = Math.max(0.2, zoom - 0.1);
    const rect = boardRef.current?.getBoundingClientRect();
    if (rect) {
      const centerX = rect.width / 2;
      const centerY = rect.height / 2;
      setBoardOffset(prev => ({
        x: prev.x + (centerX / zoom - centerX / newZoom),
        y: prev.y + (centerY / zoom - centerY / newZoom)
      }));
    }
    setZoom(newZoom);
  }, [zoom]);

  const resetZoom = useCallback(() => {
    setZoom(1);
    setBoardOffset({ x: 0, y: 0 });
  }, []);

  // ----- PNG DOWNLOAD -----
  const downloadPNG = useCallback(async () => {
    if (!boardRef.current || state.boxes.length === 0) {
      alert('Board is empty. Add some boxes first.');
      return;
    }

    const loadImage = (url) => {
      return new Promise((resolve, reject) => {
        const img = new Image();
        img.crossOrigin = 'anonymous';
        img.referrerPolicy = 'no-referrer';
        img.onload = () => resolve(img);
        img.onerror = () => {
          const img2 = new Image();
          img2.onload = () => resolve(img2);
          img2.onerror = () => reject(new Error('Failed to load image'));
          img2.src = url;
        };
        img.src = url;
      });
    };

    try {
      let minX = Infinity, minY = Infinity;
      let maxX = -Infinity, maxY = -Infinity;

      for (const box of state.boxes) {
        const boxScale = box.scale || 1;
        let width = 100, height = 80;
        if (box.isImage) {
          width = 128;
          height = 128;
        } else if (box.isLink) {
          width = Math.max(80, Math.min(200, (box.text || 'Link').length * 10 + 40));
          height = 80;
        } else {
          const textLen = (box.text || 'text').length;
          width = Math.max(80, Math.min(200, textLen * 10 + 40));
          height = Math.max(60, 80);
        }
        width *= boxScale;
        height *= boxScale;

        const left = box.x - width / 2;
        const right = box.x + width / 2;
        const top = box.y - height / 2;
        const bottom = box.y + height / 2;

        minX = Math.min(minX, left);
        minY = Math.min(minY, top);
        maxX = Math.max(maxX, right);
        maxY = Math.max(maxY, bottom);
      }

      const padding = 80;
      minX -= padding;
      minY -= padding;
      maxX += padding;
      maxY += padding;

      const boardWidth = maxX - minX;
      const boardHeight = maxY - minY;

      const tempCanvas = document.createElement('canvas');
      const tempCtx = tempCanvas.getContext('2d');
      const scale = 2;
      tempCanvas.width = boardWidth * scale;
      tempCanvas.height = boardHeight * scale;

      tempCtx.fillStyle = '#141522';
      tempCtx.fillRect(0, 0, tempCanvas.width, tempCanvas.height);

      const gridSize = 30;
      tempCtx.strokeStyle = '#32354a';
      tempCtx.lineWidth = 1;
      for (let x = 0; x <= boardWidth; x += gridSize) {
        tempCtx.beginPath();
        tempCtx.moveTo(x * scale, 0);
        tempCtx.lineTo(x * scale, tempCanvas.height);
        tempCtx.stroke();
      }
      for (let y = 0; y <= boardHeight; y += gridSize) {
        tempCtx.beginPath();
        tempCtx.moveTo(0, y * scale);
        tempCtx.lineTo(tempCanvas.width, y * scale);
        tempCtx.stroke();
      }

      for (const wire of state.wires) {
        const fromBox = state.boxes.find(b => b._id === wire.fromId);
        const toBox = state.boxes.find(b => b._id === wire.toId);
        if (!fromBox || !toBox) continue;

        const fromX = (fromBox.x - minX) * scale;
        const fromY = (fromBox.y - minY) * scale;
        const toX = (toBox.x - minX) * scale;
        const toY = (toBox.y - minY) * scale;

        const avgScale = ((fromBox.scale || 1) + (toBox.scale || 1)) / 2;
        const lineWidth = Math.max(2, 4 * avgScale) * scale;
        const wireColor = fromBox.wireColor || '#f5b042';

        tempCtx.beginPath();
        const midX = (fromX + toX) / 2;
        const midY = (fromY + toY) / 2;
        const dx = toX - fromX, dy = toY - fromY;
        const len = Math.hypot(dx, dy) || 1;
        const perpX = -dy / len * 22 * avgScale * scale;
        const perpY = dx / len * 22 * avgScale * scale;
        const seed = (parseInt(wire.fromId) * 7 + parseInt(wire.toId) * 13) % 7 - 3;
        const cpx = midX + perpX * (1 + seed * 0.25);
        const cpy = midY + perpY * (1 + seed * 0.25);
        tempCtx.moveTo(fromX, fromY);
        tempCtx.quadraticCurveTo(cpx, cpy, toX, toY);
        tempCtx.strokeStyle = wireColor;
        tempCtx.lineWidth = lineWidth;
        tempCtx.shadowColor = 'rgba(0,0,0,0.5)';
        tempCtx.shadowBlur = 8 * avgScale * scale;
        tempCtx.stroke();
        tempCtx.shadowBlur = 0;

        const dotSize = Math.max(4, 6 * avgScale) * scale;
        tempCtx.fillStyle = wireColor;
        tempCtx.beginPath();
        tempCtx.arc(fromX, fromY, dotSize, 0, 2 * Math.PI);
        tempCtx.fill();
        tempCtx.beginPath();
        tempCtx.arc(toX, toY, dotSize, 0, 2 * Math.PI);
        tempCtx.fill();
      }

      const imageCache = {};
      for (const box of state.boxes) {
        if (box.isImage && box.imageUrl) {
          try {
            const img = await loadImage(box.imageUrl);
            imageCache[box._id] = img;
          } catch (error) {
            console.warn('Failed to load image for box:', box._id, error);
            imageCache[box._id] = null;
          }
        }
      }

      for (const box of state.boxes) {
        const boxScale = box.scale || 1;
        const x = (box.x - minX) * scale;
        const y = (box.y - minY) * scale;
        const sizeScale = boxScale * scale;

        let width, height;
        if (box.isImage) {
          width = 128 * sizeScale;
          height = 128 * sizeScale;
        } else if (box.isLink) {
          width = Math.max(80, Math.min(200, (box.text || 'Link').length * 10 + 40)) * sizeScale;
          height = 80 * sizeScale;
        } else {
          const textLen = (box.text || 'text').length;
          width = Math.max(80, Math.min(200, textLen * 10 + 40)) * sizeScale;
          height = 80 * sizeScale;
        }

        const left = x - width / 2;
        const top = y - height / 2;

        tempCtx.shadowColor = 'rgba(0,0,0,0.6)';
        tempCtx.shadowBlur = 16 * sizeScale;
        tempCtx.shadowOffsetX = 0;
        tempCtx.shadowOffsetY = 4 * sizeScale;

        let bgColor = '#0b0b0b';
        if (box.isImage) bgColor = '#0a0a12';
        else if (box.isLink) bgColor = '#0a0f1a';
        tempCtx.fillStyle = bgColor;
        tempCtx.beginPath();
        const radius = 16 * sizeScale;
        tempCtx.roundRect(left, top, width, height, radius);
        tempCtx.fill();

        tempCtx.shadowBlur = 0;
        const borderColor = box.borderColor || '#b0a0ff';
        tempCtx.strokeStyle = borderColor;
        tempCtx.lineWidth = 3 * sizeScale;
        tempCtx.beginPath();
        tempCtx.roundRect(left, top, width, height, radius);
        tempCtx.stroke();

        if (box.isImage && box.imageUrl) {
          const img = imageCache[box._id];
          const imgLeft = left + 6 * sizeScale;
          const imgTop = top + 6 * sizeScale;
          const imgWidth = width - 12 * sizeScale;
          const imgHeight = height - 12 * sizeScale;

          tempCtx.save();
          tempCtx.beginPath();
          tempCtx.roundRect(imgLeft, imgTop, imgWidth, imgHeight, 10 * sizeScale);
          tempCtx.clip();

          if (img) {
            tempCtx.drawImage(img, imgLeft, imgTop, imgWidth, imgHeight);
          } else {
            tempCtx.fillStyle = '#1a1a2a';
            tempCtx.fillRect(imgLeft, imgTop, imgWidth, imgHeight);
            tempCtx.fillStyle = '#888';
            tempCtx.font = `${14 * sizeScale}px sans-serif`;
            tempCtx.textAlign = 'center';
            tempCtx.textBaseline = 'middle';
            tempCtx.fillText('🖼️', imgLeft + imgWidth / 2, imgTop + imgHeight / 2);
          }
          tempCtx.restore();
        } else {
          const textColor = box.textColor || (box.isLink ? '#4a9eff' : '#f0f0f0');
          tempCtx.fillStyle = textColor;
          const fontSize = Math.max(12, 16 * sizeScale);
          tempCtx.font = `600 ${fontSize}px 'Segoe UI', sans-serif`;
          tempCtx.textAlign = 'center';
          tempCtx.textBaseline = 'middle';
          const text = box.text || (box.isLink ? 'Link' : 'text');

          if (box.isLink) {
            tempCtx.fillText(text, left + width / 2, top + height / 2 - 10 * sizeScale);
            tempCtx.fillStyle = '#666';
            tempCtx.font = `${fontSize * 0.5}px 'Segoe UI', sans-serif`;
            const displayUrl = box.linkUrl || 'No URL';
            const shortUrl = displayUrl.length > 30 ? displayUrl.substring(0, 27) + '...' : displayUrl;
            tempCtx.fillText(shortUrl, left + width / 2, top + height / 2 + 16 * sizeScale);
          } else {
            const words = text.split(' ');
            let lines = [];
            let currentLine = '';
            for (const word of words) {
              const testLine = currentLine + (currentLine ? ' ' : '') + word;
              const metrics = tempCtx.measureText(testLine);
              if (metrics.width > width - 20 * sizeScale && currentLine) {
                lines.push(currentLine);
                currentLine = word;
              } else {
                currentLine = testLine;
              }
            }
            if (currentLine) lines.push(currentLine);
            const lineHeight = fontSize * 1.3;
            const totalHeight = lines.length * lineHeight;
            const startY = top + height / 2 - totalHeight / 2 + lineHeight / 2;
            for (let i = 0; i < lines.length; i++) {
              tempCtx.fillText(lines[i], left + width / 2, startY + i * lineHeight);
            }
          }
        }
      }

      const link = document.createElement('a');
      link.download = 'board.png';
      link.href = tempCanvas.toDataURL('image/png');
      link.click();
    } catch (error) {
      console.error('Error downloading PNG:', error);
      alert('Error downloading PNG. Please try again.');
    }
  }, [state.boxes, state.wires]);

  // ----- DRAG AND SELECTION HANDLING -----
  const handleBoxMouseDown = useCallback((e, box) => {
    if (e.target.closest('.color-row') || e.target.closest('.resize-handle') || 
        e.target.closest('.redirect-btn') || e.target.closest('.delete-btn')) {
      return;
    }

    mouseDownTime.current = Date.now();
    mouseDownPos.current = { x: e.clientX, y: e.clientY };

    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      setSelectedIds(prev => {
        const newSet = new Set(prev);
        if (newSet.has(box._id)) {
          newSet.delete(box._id);
        } else {
          newSet.add(box._id);
        }
        return newSet;
      });
      return;
    }

    if (!e.ctrlKey && !e.metaKey) {
      setSelectedIds(new Set([box._id]));
      
      const rect = boardRef.current.getBoundingClientRect();
      setDragging(box._id);
      isDraggingRef.current = true;
      setDragOffset({
        x: (e.clientX - rect.left) / zoom - box.x,
        y: (e.clientY - rect.top) / zoom - box.y
      });
      dragStartPosition.current = { x: box.x, y: box.y };
    }
  }, [zoom]);

  const handleMouseMove = useCallback((e) => {
    if (!dragging || !isDraggingRef.current) return;
    
    const dx = Math.abs(e.clientX - mouseDownPos.current.x);
    const dy = Math.abs(e.clientY - mouseDownPos.current.y);
    if (dx < 3 && dy < 3) return;
    
    const rect = boardRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / zoom - dragOffset.x;
    const y = (e.clientY - rect.top) / zoom - dragOffset.y;
    
    const updatedBox = state.boxes.find(b => b._id === dragging);
    if (updatedBox) {
      const newBox = { ...updatedBox, x, y };
      dispatch({ type: 'UPDATE_BOX', box: newBox });
    }
  }, [dragging, dragOffset, zoom, state.boxes]);

  const handleMouseUp = useCallback((e) => {
    if (dragging && isDraggingRef.current) {
      const finalBox = state.boxes.find(b => b._id === dragging);
      if (finalBox && dragStartPosition.current) {
        const dx = Math.abs(finalBox.x - dragStartPosition.current.x);
        const dy = Math.abs(finalBox.y - dragStartPosition.current.y);
        if (dx > 1 || dy > 1) {
          if (socket && isConnected) {
            socket.emit('position-changed', {
              boxId: dragging,
              x: finalBox.x,
              y: finalBox.y
            });
          }
          saveBoard();
        }
      }
      setDragging(null);
      isDraggingRef.current = false;
      dragStartPosition.current = null;
    }
  }, [dragging, state.boxes, socket, isConnected, saveBoard]);

  const handleBoxClick = useCallback((e, box) => {
    if (e.target.closest('.color-row') || e.target.closest('.resize-handle') || 
        e.target.closest('.redirect-btn') || e.target.closest('.delete-btn')) {
      return;
    }

    const timeDiff = Date.now() - mouseDownTime.current;
    const dx = Math.abs(e.clientX - mouseDownPos.current.x);
    const dy = Math.abs(e.clientY - mouseDownPos.current.y);
    
    if (dx > 5 || dy > 5 || timeDiff > 300) return;

    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      return;
    }

    setSelectedIds(new Set([box._id]));
  }, []);

  // ----- RESIZE HANDLING -----
  const handleResizeStart = useCallback((e, box) => {
    e.stopPropagation();
    e.preventDefault();
    
    isResizing.current = true;
    resizeBoxId.current = box._id;
    resizeStartScale.current = box.scale || 1;
    resizeCurrentScale.current = box.scale || 1;
    resizeStartPos.current = { x: box.x, y: box.y };
    
    const startX = e.clientX;
    const startY = e.clientY;
    
    const onMove = (ev) => {
      if (!isResizing.current) return;
      
      const delta = (ev.clientX - startX + ev.clientY - startY) * 0.005;
      const newScale = Math.max(0.2, Math.min(5, resizeStartScale.current + delta));
      resizeCurrentScale.current = newScale;
      
      const updatedBox = state.boxes.find(b => b._id === resizeBoxId.current);
      if (updatedBox) {
        const newBox = { 
          ...updatedBox, 
          scale: newScale,
          x: resizeStartPos.current.x,
          y: resizeStartPos.current.y
        };
        dispatch({ type: 'UPDATE_BOX', box: newBox });
      }
    };
    
    const onUp = () => {
      if (isResizing.current && resizeBoxId.current) {
        const finalBox = state.boxes.find(b => b._id === resizeBoxId.current);
        if (finalBox) {
          const preservedBox = {
            ...finalBox,
            scale: resizeCurrentScale.current,
            x: resizeStartPos.current.x,
            y: resizeStartPos.current.y
          };
          
          dispatch({ type: 'UPDATE_BOX', box: preservedBox });
          
          if (socket && isConnected) {
            socket.emit('box-updated', { box: preservedBox });
          }
          
          saveBoard();
        }
      }
      
      isResizing.current = false;
      resizeBoxId.current = null;
      resizeStartScale.current = 1;
      resizeCurrentScale.current = 1;
      resizeStartPos.current = { x: 0, y: 0 };
      
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
    };
    
    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
  }, [state.boxes, socket, isConnected, saveBoard]);

  // Global mouse events
  useEffect(() => {
    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };
  }, [handleMouseMove, handleMouseUp]);

  // Board pan
  const handleBoardMouseDown = useCallback((e) => {
    if (e.target.closest('.box') || e.target.closest('.color-row') || e.target.closest('canvas')) return;
    setIsPanning(true);
    setPanStart({ x: e.clientX, y: e.clientY });
  }, []);

  const handleBoardMouseMovePan = useCallback((e) => {
    if (!isPanning) return;
    const dx = e.clientX - panStart.x;
    const dy = e.clientY - panStart.y;
    setBoardOffset(prev => ({
      x: prev.x + dx / zoom,
      y: prev.y + dy / zoom
    }));
    setPanStart({ x: e.clientX, y: e.clientY });
  }, [isPanning, panStart, zoom]);

  const handleBoardMouseUp = useCallback(() => {
    setIsPanning(false);
  }, []);

  // Wheel zoom
  const handleWheel = useCallback((e) => {
    e.preventDefault();
    const rect = boardRef.current.getBoundingClientRect();
    const mouseX = (e.clientX - rect.left) / zoom;
    const mouseY = (e.clientY - rect.top) / zoom;
    
    const delta = e.deltaY > 0 ? -0.1 : 0.1;
    const newZoom = Math.min(3, Math.max(0.2, zoom + delta));
    
    setZoom(newZoom);
    setBoardOffset(prev => ({
      x: prev.x + (mouseX - prev.x) * (1 - zoom / newZoom),
      y: prev.y + (mouseY - prev.y) * (1 - zoom / newZoom)
    }));
  }, [zoom]);

  // Canvas drawing
  useEffect(() => {
    if (!canvasRef.current || !boardRef.current) return;
    
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const rect = boardRef.current.getBoundingClientRect();
    
    canvas.width = rect.width;
    canvas.height = rect.height;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    state.wires.forEach(wire => {
      const fromBox = state.boxes.find(b => b._id === wire.fromId);
      const toBox = state.boxes.find(b => b._id === wire.toId);
      if (!fromBox || !toBox) return;

      const fromDiv = document.querySelector(`[data-id="${fromBox._id}"]`);
      const toDiv = document.querySelector(`[data-id="${toBox._id}"]`);
      if (!fromDiv || !toDiv) return;

      const fromRect = fromDiv.getBoundingClientRect();
      const toRect = toDiv.getBoundingClientRect();
      const boardRect = boardRef.current.getBoundingClientRect();

      const x1 = fromRect.left + fromRect.width/2 - boardRect.left;
      const y1 = fromRect.top + fromRect.height/2 - boardRect.top;
      const x2 = toRect.left + toRect.width/2 - boardRect.left;
      const y2 = toRect.top + toRect.height/2 - boardRect.top;

      const avgScale = ((fromBox.scale || 1) + (toBox.scale || 1)) / 2;
      const lineWidth = Math.max(1.5, 4 * zoom * avgScale);

      ctx.beginPath();
      const midX = (x1 + x2) / 2;
      const midY = (y1 + y2) / 2;
      const dx = x2 - x1, dy = y2 - y1;
      const len = Math.hypot(dx, dy) || 1;
      const perpX = -dy / len * 22 * zoom * avgScale;
      const perpY = dx / len * 22 * zoom * avgScale;
      const seed = (parseInt(wire.fromId) * 7 + parseInt(wire.toId) * 13) % 7 - 3;
      const cpx = midX + perpX * (1 + seed * 0.25);
      const cpy = midY + perpY * (1 + seed * 0.25);
      
      ctx.moveTo(x1, y1);
      ctx.quadraticCurveTo(cpx, cpy, x2, y2);
      ctx.strokeStyle = fromBox.wireColor || '#f5b042';
      ctx.lineWidth = lineWidth;
      ctx.shadowColor = 'rgba(0,0,0,0.5)';
      ctx.shadowBlur = 8 * zoom * avgScale;
      ctx.stroke();
      ctx.shadowBlur = 0;

      const dotSize = Math.max(3, 6 * zoom * avgScale);
      ctx.fillStyle = fromBox.wireColor || '#f5b042';
      ctx.beginPath();
      ctx.arc(x1, y1, dotSize, 0, 2 * Math.PI);
      ctx.fill();
      ctx.beginPath();
      ctx.arc(x2, y2, dotSize, 0, 2 * Math.PI);
      ctx.fill();
    });
  }, [state.boxes, state.wires, zoom, boardOffset]);

  // Helper function to render color row for image boxes
  const renderImageColorRow = (box) => {
    const boxScale = box.scale || 1;
    const imageSize = 128 * boxScale * zoom;
    const posX = (box.x + boardOffset.x) * zoom;
    const posY = (box.y + boardOffset.y) * zoom + imageSize + 4;
    
    // Scale the color row with the box
    const colorRowScale = boxScale * zoom;
    
    return (
      <div
        key={`color-${box._id}`}
        className="color-row image-color-row"
        style={{
          position: 'absolute',
          left: posX,
          top: posY,
          transform: `scale(${colorRowScale})`,
          transformOrigin: 'top left',
          display: 'flex',
          gap: '4px',
          background: '#1c1c2a',
          padding: '4px 8px',
          borderRadius: '30px',
          alignItems: 'center',
          border: '1px solid #3a3d55',
          zIndex: 15,
          pointerEvents: 'auto',
          whiteSpace: 'nowrap'
        }}
        onMouseDown={(e) => e.stopPropagation()}
        onClick={(e) => e.stopPropagation()}
      >
        <label style={{ display: 'flex', alignItems: 'center', gap: '3px', fontSize: '0.5rem', color: '#bcc0db', cursor: 'pointer' }}>
          🔲
          <input
            type="color"
            value={box.borderColor || '#b0a0ff'}
            onChange={(e) => handleColorChange(e, box, 'borderColor')}
            style={{
              width: '18px',
              height: '18px',
              border: '1px solid #5a5d7a',
              borderRadius: '30px',
              background: 'transparent',
              cursor: 'pointer',
              padding: '1px'
            }}
          />
        </label>
        <label style={{ display: 'flex', alignItems: 'center', gap: '3px', fontSize: '0.5rem', color: '#bcc0db', cursor: 'pointer' }}>
          〰️
          <input
            type="color"
            value={box.wireColor || '#f5b042'}
            onChange={(e) => handleColorChange(e, box, 'wireColor')}
            style={{
              width: '18px',
              height: '18px',
              border: '1px solid #5a5d7a',
              borderRadius: '30px',
              background: 'transparent',
              cursor: 'pointer',
              padding: '1px'
            }}
          />
        </label>
      </div>
    );
  };

  if (isLoading) {
    return (
      <div className="loading-container">
        <div className="loading-content">
          <div className="loading-icon">🧩</div>
          <div className="loading-text">Loading global board...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="board-container">
      {/* Image Modal */}
      {showImageModal && (
        <div className="modal-overlay active" onClick={() => setShowImageModal(false)}>
          <div className="modal-box" onClick={(e) => e.stopPropagation()}>
            <h3>🖼️ Enter Image URL</h3>
            <div className="modal-row">
              <input
                type="text"
                className="modal-input"
                placeholder="https://example.com/image.jpg"
                value={imageUrl}
                onChange={(e) => setImageUrl(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') addImageBox();
                  if (e.key === 'Escape') setShowImageModal(false);
                }}
                autoFocus
              />
            </div>
            <div className="modal-actions">
              <button className="btn" onClick={() => setShowImageModal(false)}>Cancel</button>
              <button className="btn btn-success" onClick={addImageBox}>Add Image</button>
            </div>
          </div>
        </div>
      )}

      {/* Link Modal */}
      {showLinkModal && (
        <div className="modal-overlay active" onClick={() => setShowLinkModal(false)}>
          <div className="modal-box" onClick={(e) => e.stopPropagation()}>
            <h3>🔗 Add Link</h3>
            <div className="modal-row">
              <label>Title</label>
              <input
                type="text"
                className="modal-input"
                placeholder="My Website"
                value={linkTitle}
                onChange={(e) => setLinkTitle(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') document.getElementById('linkUrlInput').focus();
                  if (e.key === 'Escape') setShowLinkModal(false);
                }}
                autoFocus
              />
            </div>
            <div className="modal-row">
              <label>URL</label>
              <input
                id="linkUrlInput"
                type="text"
                className="modal-input"
                placeholder="https://example.com"
                value={linkUrl}
                onChange={(e) => setLinkUrl(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') addLinkBox();
                  if (e.key === 'Escape') setShowLinkModal(false);
                }}
              />
            </div>
            <div className="modal-actions">
              <button className="btn" onClick={() => setShowLinkModal(false)}>Cancel</button>
              <button className="btn btn-info" onClick={addLinkBox}>Add Link</button>
            </div>
          </div>
        </div>
      )}

      <div className="board-header">
        <div className="header-left">
          <h2>🧩 Global Board</h2>
          <span className="board-name">Collaborative Whiteboard</span>
          <span className={`connection-status ${isConnected ? 'connected' : 'disconnected'}`}>
            {isConnected ? '● Online' : '○ Offline'}
          </span>
          <span className="collaborator-count">
            👥 {users.length} online
          </span>
          {isSaving && <span className="saving-status">💾 Saving...</span>}
        </div>
        <div className="header-center">
          <button className="btn" onClick={addTextBox}>📝 Text</button>
          <button className="btn btn-success" onClick={() => setShowImageModal(true)}>🖼️ Image</button>
          <button className="btn btn-info" onClick={() => setShowLinkModal(true)}>🔗 Link</button>
          <button className="btn btn-primary" onClick={connectSelected}>🔗 Connect</button>
          <button className="btn btn-danger" onClick={disconnectSelected}>🔌 Disconnect</button>
          <button className="btn btn-danger" onClick={deleteSelected}>🗑️ Delete</button>
          <button className="btn btn-warning" onClick={downloadPNG}>📥 PNG</button>
        </div>
        <div className="header-right">
          <div className="zoom-controls">
            <button className="btn btn-small" onClick={zoomOut}>➖</button>
            <span className="zoom-level">{Math.round(zoom * 100)}%</span>
            <button className="btn btn-small" onClick={zoomIn}>➕</button>
            <button className="btn btn-small" onClick={resetZoom}>⟲</button>
          </div>
          <div className="active-users">
            <span className="user-count">{users.length} online</span>
            <div className="user-avatars">
              {users.slice(0, 5).map(u => (
                <span key={u._id} className="user-avatar" title={u.username}>
                  {u.username.charAt(0).toUpperCase()}
                </span>
              ))}
              {users.length > 5 && <span className="user-avatar more">+{users.length - 5}</span>}
            </div>
          </div>
          {user && user.role === 'admin' && (
            <button className="btn btn-warning" onClick={() => window.location.href = '#/admin'}>⚙️ Admin</button>
          )}
          <button className="btn" onClick={() => window.location.href = '#/login'}>🚪 Logout</button>
        </div>
      </div>
      <div 
        className="board-wrapper"
        ref={boardRef}
        onMouseDown={handleBoardMouseDown}
        onMouseMove={handleBoardMouseMovePan}
        onMouseUp={handleBoardMouseUp}
        onMouseLeave={handleBoardMouseUp}
        onWheel={handleWheel}
      >
        <div className="board-content">
          {state.boxes.map(box => {
            return (
              <div
                key={box._id}
                data-id={box._id}
                className={`box ${selectedIds.has(box._id) ? 'selected' : ''}`}
                style={{
                  transform: `translate(${(box.x + boardOffset.x) * zoom}px, ${(box.y + boardOffset.y) * zoom}px) scale(${(box.scale || 1) * zoom})`,
                  borderColor: box.borderColor,
                  ...(box.isImage && {
                    width: '128px',
                    height: '128px',
                    padding: '4px',
                    minWidth: '128px',
                    minHeight: '128px',
                    overflow: 'hidden'
                  }),
                  ...(box.isLink && {
                    background: '#0a0f1a',
                    minWidth: '80px',
                    minHeight: '60px',
                    padding: '8px 12px'
                  })
                }}
                onMouseDown={(e) => handleBoxMouseDown(e, box)}
                onClick={(e) => handleBoxClick(e, box)}
                onDoubleClick={(e) => {
                  if (box.isImage && box.imageUrl) {
                    e.stopPropagation();
                    openImageZoom(box.imageUrl, box.text);
                  } else if (box.isLink) {
                    e.stopPropagation();
                    setLinkTitle(box.text || '');
                    setLinkUrl(box.linkUrl || '');
                    setShowLinkModal(true);
                    const editBox = box;
                    const editLinkBox = () => {
                      if (!linkUrl.trim()) {
                        alert('Please enter a URL');
                        return;
                      }
                      if (!linkTitle.trim()) {
                        alert('Please enter a title');
                        return;
                      }
                      try {
                        new URL(linkUrl);
                      } catch (e) {
                        alert('Please enter a valid URL (include https://)');
                        return;
                      }
                      const updatedBox = { ...editBox, text: linkTitle, linkUrl: linkUrl };
                      updateBox(updatedBox);
                      setLinkTitle('');
                      setLinkUrl('');
                      setShowLinkModal(false);
                    };
                    setTimeout(() => {
                      const confirmBtn = document.querySelector('.modal-actions .btn-info');
                      if (confirmBtn) {
                        confirmBtn.onclick = editLinkBox;
                      }
                    }, 100);
                  }
                }}
              >
                {selectedIds.has(box._id) && (
                  <div 
                    className="delete-btn"
                    onClick={(e) => {
                      e.stopPropagation();
                      setSelectedIds(new Set([box._id]));
                      deleteSelected();
                    }}
                  >
                    ✕
                  </div>
                )}
                {box.isImage ? (
                  <div className="image-container">
                    {box.imageUrl ? (
                      <img 
                        src={box.imageUrl} 
                        alt={box.text} 
                        draggable="false" 
                        loading="lazy" 
                        style={{ 
                          width: '100%', 
                          height: '100%', 
                          objectFit: 'contain',
                          display: 'block'
                        }} 
                      />
                    ) : (
                      <div className="image-placeholder">🖼️ no image</div>
                    )}
                  </div>
                ) : box.isLink ? (
                  <>
                    <input
                      type="text"
                      className="box-text"
                      value={box.text || 'Link'}
                      style={{ color: box.textColor || '#4a9eff' }}
                      onChange={(e) => {
                        const newBox = { ...box, text: e.target.value };
                        updateBox(newBox);
                      }}
                      onClick={(e) => {
                        e.stopPropagation();
                        if (box.linkUrl) window.open(box.linkUrl, '_blank');
                      }}
                      onMouseDown={(e) => e.stopPropagation()}
                    />
                    <button
                      className="redirect-btn"
                      onClick={(e) => {
                        e.stopPropagation();
                        if (box.linkUrl) window.open(box.linkUrl, '_blank');
                      }}
                    >
                      ↗
                    </button>
                  </>
                ) : (
                  <input
                    type="text"
                    className="box-text"
                    value={box.text || 'text'}
                    style={{ color: box.textColor || '#f0f0f0' }}
                    onChange={(e) => {
                      const newBox = { ...box, text: e.target.value };
                      updateBox(newBox);
                    }}
                    onMouseDown={(e) => e.stopPropagation()}
                    onClick={(e) => e.stopPropagation()}
                  />
                )}
                {/* Color row for non-image boxes (inside the box) */}
                {!box.isImage && (
                  <div className="color-row" onMouseDown={(e) => e.stopPropagation()}>
                    <label>🔲
                      <input
                        type="color"
                        value={box.borderColor || '#b0a0ff'}
                        onChange={(e) => handleColorChange(e, box, 'borderColor')}
                      />
                    </label>
                    {!box.isImage && (
                      <label>🅰️
                        <input
                          type="color"
                          value={box.textColor || (box.isLink ? '#4a9eff' : '#f0f0f0')}
                          onChange={(e) => handleColorChange(e, box, 'textColor')}
                        />
                      </label>
                    )}
                    <label>〰️
                      <input
                        type="color"
                        value={box.wireColor || '#f5b042'}
                        onChange={(e) => handleColorChange(e, box, 'wireColor')}
                      />
                    </label>
                  </div>
                )}
                <div
                  className="resize-handle"
                  onMouseDown={(e) => handleResizeStart(e, box)}
                />
              </div>
            );
          })}
          {/* Color rows for image boxes - positioned outside the box */}
          {state.boxes.filter(b => b.isImage).map(box => renderImageColorRow(box))}
          <canvas ref={canvasRef} className="wire-canvas" />
        </div>
      </div>
    </div>
  );
};

export default Board;